# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, exceptions as es_exceptions
import os
import re
from functools import lru_cache

app = Flask(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
ES_TIMEOUT = float(os.getenv("ELASTICSEARCH_TIMEOUT", "2.0"))
ES_MAX_RETRIES = int(os.getenv("ELASTICSEARCH_MAX_RETRIES", "2"))
ES_RETRY_ON_TIMEOUT = os.getenv("ELASTICSEARCH_RETRY_ON_TIMEOUT", "true").lower() == "true"

es = Elasticsearch(
    ES_URL,
    request_timeout=ES_TIMEOUT,
    max_retries=ES_MAX_RETRIES,
    retry_on_timeout=ES_RETRY_ON_TIMEOUT,
    http_compress=True,
)

QUERY_RE = re.compile(r"\S+")


def _normalize_query(q):
    if q is None:
        return ""
    q = q.strip()
    if len(q) > 200:
        q = q[:200]
    return q


@lru_cache(maxsize=5000)
def _search_cached(q):
    body = {
        "size": 20,
        "track_total_hits": False,
        "_source": ["id", "name", "price", "image_url", "sku", "brand", "category"],
        "query": {
            "multi_match": {
                "query": q,
                "fields": [
                    "name^4",
                    "brand^3",
                    "category^2",
                    "sku^5",
                    "description"
                ],
                "type": "best_fields",
                "operator": "and",
                "fuzziness": "AUTO"
            }
        },
        "sort": [
            "_score",
            {"popularity": "desc"},
            {"updated_at": "desc"}
        ]
    }
    return es.search(index=ES_INDEX, body=body)


@app.route("/api/search", methods=["GET"])
def search_products():
    q = _normalize_query(request.args.get("q", ""))
    if not q:
        return jsonify({"query": q, "count": 0, "results": []}), 200

    try:
        resp = _search_cached(q)
        hits = resp.get("hits", {}).get("hits", [])
        results = []
        for hit in hits:
            source = hit.get("_source", {})
            results.append({
                "id": source.get("id", hit.get("_id")),
                "name": source.get("name"),
                "price": source.get("price"),
                "image_url": source.get("image_url"),
                "sku": source.get("sku"),
                "brand": source.get("brand"),
                "category": source.get("category"),
                "score": hit.get("_score", 0),
            })
        return jsonify({
            "query": q,
            "count": len(results),
            "results": results
        }), 200
    except es_exceptions.NotFoundError:
        return jsonify({"query": q, "count": 0, "results": []}), 200
    except (es_exceptions.ConnectionError, es_exceptions.TransportError, es_exceptions.ApiError):
        return jsonify({"error": "search_unavailable"}), 503
    except Exception:
        return jsonify({"error": "internal_server_error"}), 500


@app.after_request
def add_headers(response):
    response.headers["Cache-Control"] = "public, max-age=30, stale-while-revalidate=60"
    return response


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))